  ('观音桥', 4, '', '观音桥九街（不夜九街 - 终点）', '', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/chongqing_guanyinqiao_sa_05.jpg'),
  ('洪崖洞民俗风貌区', 0, 'Chongqing Hongyadong Folk Custom Scenic Area', '重庆洪崖洞民俗风貌区', '<p>Built on a 79-metre cliff above the confluence of the Yangtze and Jialing rivers, Hongyadong is an 11-storey stilted-house complex of 65,000 m² designed by He Yongzhi in 2006. Inspired by Bayu traditional architecture, its tiered wooden pavilions, flying eaves and grey brick walls have become a viral symbol of Chongqing''s "Mountain City" nightscape. The complex is a national night-time cultural-tourism zone linking Chaotianmen Square, Jiefangbei and the Qiansimen Bridge.</p>', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/chongqing_hongya_cave_sa_01.jpg'),
  ('洪崖洞民俗风貌区', 1, '6F: Light & Shadow Interactive Art Space', '六楼:光影互动艺术空间', '<p>Located on the 6th floor, this 1,800 m² immersive art space was co-curated by the Sichuan Fine Arts Institute''s new-media team and invited teamLab artists. Ten permanent themed rooms include the radar-sensor "Rain Room," interactive "Flower Field," 180° dome "Star Room," koi-filled "Deep Sea," 36-mirror "Mirror Palace" and a 360° Chongqing-night panorama. Exhibits rotate every 6–12 months and the venue hosts the annual Chongqing International Light &amp; Shadow Art Festival.</p>', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/chongqing_hongya_cave_sa_02.png'),
  ('洪崖洞民俗风貌区', 2, '5F: Reunion 1980 — 80s Life Streetscape', '五楼:重逢 1980·八十年代生活情境街区', '<p>Reunion 1980 on the 5th floor (~5,000 m²) is a 1:1 recreation of 1980–1989 Chongqing life by the Qi Chou Hou creative team. Six themed sets — an old hotpot shop, a Shiba-ti barbershop, the Jiefangbei Xinhua Bookstore, a "Mountain City" wide-screen cinema, the Chaotianmen cable station and a teahouse — host 30+ interactive rooms (80s living room with a black-and-white TV, sewing machine and enamel basin; classroom with abacus and Little Red Book; photo studio with Haiou camera). Period-costume rentals and roving "ice-cream vendor / knife-sharpener / popcorn man" performers (15:00–16:00) make it a nostalgia, family and influencer destination.</p>', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/chongqing_hongya_cave_sa_03.jpg'),
  ('洪崖洞民俗风貌区', 3, '4F: Grand Feast Food Street', '四楼:盛宴美食街', '<p>The 350-metre Grand Feast Food Street on Level 4 is Hongyadong''s culinary core. Section A serves classic Chongqing dishes (hotpot, Miaojiang chicken offal, Bishan rabbit, Laifeng fish); Section B offers Sichuan street snacks (sour-spicy noodles, cold noodles, bo-bo chicken, guokui, chuanchuan); Section C imports 30+ national brands (Shunde congee, Nanjing Da Pai Dang, Guizhou Siwa Wa, Hunan cured meat, Shaanxi biangbiang noodles). A covered arcade echoes the stilted-house façade; the daily 18:00–21:00 "Jianghu Cuisine" long-table banquet seats up to 200 guests.</p>', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/chongqing_hongya_cave_sa_04.jpg'),
  ('洪崖洞民俗风貌区', 4, '3F: Tiancheng Lane Bayu Folk Street', '三楼:天成巷巴渝风情街', '<p>Named after the old Tiancheng Lane of the historical Chongqing city, this 280-metre street is the intangible-heritage core. The east section hosts 12 workshops (Shu embroidery, Rongchang fans, Rongchang pottery, Liangping bamboo curtains, Chengkou lacquer, Youyang Miao embroidery) with master demonstrations; the central section gathers Chongqing geographical-indication brands (Qiaotou hotpot base, Ciqikou Chen mahua, Hechuan taoshan, Jiangjin mihuatang, Fuling zhacai); the western section carries 30 local designer brands. The level is Hongyadong''s main souvenir economy.</p>', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/chongqing_hongya_cave_sa_05.jpg'),
  ('洪崖洞民俗风貌区', 5, '2F: Zhi-Yan River Dynamic Bar Street', '二楼:纸盐河动感酒吧街', '<p>The 220-metre Zhi-Yan River Bar Street on Level 2 — named after the historic paper-and-salt-trade dock lane — is one of Chongqing''s three great nightlife strips. Section A hosts cocktail, single-malt and sake bars with floor-to-ceiling glass over the Jialing River and Qiansimen Bridge; Section B gathers 8 live-music brands (SPACE, MAO LiveHouse, Nut Club, etc.) with 20:30–23:00 shows nightly; Section C houses clubs (SOHO, SPACE MIX, MUSE) open until 04:00.</p>', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/chongqing_hongya_cave_sa_06.jpg'),
  ('洪崖洞民俗风貌区', 6, '1F: Dichiui (Dripping-Greenery) Plaza', '一楼:滴翠广场', '<p>The 3,500 m² Dichiui Plaza on Level 1 is Hongyadong''s ground floor and main access hub, linking Cangbai Road (north) to the Jiabin Road riverside (south). A sunken "Mountain-City Green Island" with stacked rocks, banyan and maple trees anchors the center. Tiered steps lead down to the riverfront walkway; to the south stands the "River Fort" bronze sculpture; to the north lies the Qiansimen Bridge east-abutment — the spot for the classic Hongyadong-at-night shot from the Grand Theater side.</p>', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/chongqing_hongya_cave_sa_07.jpg'),
  ('洪崖洞民俗风貌区', 7, 'City Balcony', '城市阳台', '<p>The City Balcony crowns Hongyadong at level 11 (~79 m above the river). Facing north, it overlooks Jiangbeizui''s skyline; south, the Yangtze–Jialing confluence ("yin-yang hotpot") and the Chaotianmen Rafles complex; east, the iconic photo spot combining the stilted houses with the Qiansimen Bridge. With cafés, souvenir shops and small exhibitions, it is the prime night-photography point.</p>', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/chongqing_hongya_cave_sa_08.jpg'),
  ('洪崖洞民俗风貌区', 8, 'Xinhai Revolutionary Monument', '辛亥丰碑', '<p>Located on the western side of Hongyadong''s City Balcony plaza, the Xinhai Monument is a black-granite relief wall honoring the 1911 Revolution in Chongqing. The relief depicts Zhang Peijue, Yang Cangbai and Xiang Chu — leaders of the November 22, 1911 uprising that established the Shu Army Government — alongside soldiers, banners and the old Chaotianmen docks. It anchors Hongyadong''s role as a civic-historical landmark.</p>', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/chongqing_hongya_cave_sa_09.jpg'),
  ('洪崖洞民俗风貌区', 9, 'Memory of the Mountain City Sculpture', '记忆山城雕塑', '<p>Distributed across the corridors of Hongyadong''s 11F-to-1F levels, this bronze-relief cluster re-imagines late 19th- to mid 20th-century Chongqing life: the Chaotianmen cable car, sedan-chair porters, stilted-house kitchens, riverside laundry and the famous "bangbang" porters. Produced over two years by a Sichuan Fine Arts Institute team, it functions as a "Chongqing Along-the-River-During-the-Qingming-Festival" of the old Mountain City.</p>', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/chongqing_hongya_cave_sa_10.jpg'),
  ('洪崖洞民俗风貌区', 10, 'River-Blockade Fort Bronze Sculpture', '江隘炮台铜雕', '<p>Placed on the riverside terrace beside the 1F Dichiui Plaza, this bronze fort sculpture commemorates the river-defence system of the upper Yangtze from 1891 through the 1937–1945 war years. The main piece is a Krupp-style coastal gun aimed downstream; the relief base depicts the Battle of Yichang, the Shiplap Defense and the Great Yichang Retreat, flanked by three Sichuan Army soldiers and a bugler. A rubbing of Feng Yuxiang''s "Return Our Land" calligraphy is inscribed at the rear.</p>', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/chongqing_hongya_cave_sa_11.jpg'),
  ('洪崖洞民俗风貌区', 11, '10F: Ba Culture Pillars', '十楼:巴文化柱', '<p>The 10th-floor central atrium is anchored by six 8-metre carved bluestone pillars designed by the Sichuan Fine Arts Institute, tracing Ba civilization from its mythic origins to the Qin–Han era. Topics span Ba migrations, fishing/hunting/agriculture, salt and cinnabar trade, the "Xialiba" war-dance, the white-tiger totem and the eventual disappearance of the Ba script. Bronze bird-zun replicas top each pillar, and bilingual Ba/Han inscriptions line the walls.</p>', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/chongqing_hongya_cave_sa_12.jpg'),
  ('洪崖洞民俗风貌区', 12, '9F: Exotic Flavors Street', '九楼:异域风情街', '<p>The 120-metre Exotic Flavors Street on Level 9 is divided into four themed zones — Southeast Asia, the Middle East, Europe and the Americas — housing about 30 themed restaurants, cafés and craft stores. Facades mix Ottoman arches, rattan lanterns, Islamic geometric tiles and Mayan motifs. Weekend afternoons (16:00–17:00) feature a rotating program of street music and dance; the level forms a "Chongqing meets the world" counterpart to the Ba culture pillars above.</p>', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/chongqing_hongya_cave_sa_13.jpg'),
  ('洪崖洞民俗风貌区', 13, '8F: Zone 78 Trendy-Play World', '八楼:78 区潮玩世界', '<p>Zone 78 on the 8th floor (~4,000 m²) is Chongqing''s Gen-Z hangout: a streetwear district (INXX, Randomevent, ROARINGWILD), a blind-box and figure district (Pop Mart, TOPTOY, 52TOYS), six headquarter murder-mystery and escape-room stores, plus a skate/dance/b-box shared space. Weekend "Zone 78 Street Culture Festival" mini-markets have made it the city''s primary Gen-Z check-in spot.</p>', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/chongqing_hongya_cave_sa_14.jpg'),
  ('洪崖洞民俗风貌区', 14, '7F: Zone 78 Trendy-Play World (Lower Level)', '七楼:78 区潮玩世界', '<p>The 7F is the lower half of Zone 78, linked to 8F by the central atrium. It adds a "Guochao / ACG / e-sports" identity: Zone E hosts 20+ national-style brands (Hanfu, intangible-heritage crafts and Cha Yan Yue Se tea); Zone F is a 1,500 m² ACG hub hosting BJD doll shows, Lolita tea parties and ComiC Chongqing sub-venues; Zone G is the 78 E-sports Arena, with 12 five-seat rooms, 8 streamer booths and a 60-seat LPL-themed viewing hall — the main campus-league venue in central Chongqing.</p>', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/chongqing_hongya_cave_sa_15.png'),
  ('金佛山', 0, '', '大门', '<p>The Main Gate sits at the foot of Jinfo Mountain''s north slope near Tianxing Town and serves as the first stop for most visitors. The entrance complex combines a large parking lot, visitor center, ticket windows and self-service kiosks where combined tickets for admission, cableway and shuttle can be purchased. An eco-shuttle bus ride of about 20 minutes reaches the cableway lower station, passing lower-zone sights such as Bitan Valley. The visitor center offers panoramic maps, rain-poncho rental and luggage storage, and doubles as the registration point for winter ski equipment. Outside the gate, Tianxing Town provides dining, lodging and specialty shops—a common base for two-day "valley-to-summit" itineraries.</p>', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/chongqing_jinfo_mountain_sa_01.jpg'),
  ('金佛山', 1, '', '药池坝', '<p>Yaochiba sits southwest of Qianniuping at about 2,000 m—a roughly 30,000 m² alpine meadow and wetland complex. The flat, grassy expanse is dotted with dozens of natural mineral springs and pools; Jinfo Mountain monks once drew water here to brew herbal remedies, giving the place its name ("Medicine Pool"). Surrounded by arrow bamboo and rhododendron shrub, with the Jinfo summit ridge and karst pinnacles on the horizon, the meadow turns golden in autumn against layered forests—one of the mountain''s signature fall scenes. Boardwalks, rest pavilions and viewing platforms are provided, and the dam is a popular camping and stargazing spot. Westward trails lead to Ancient Buddha Cave and Jinfo Temple; southward to the Ecological Stone Forest.</p>', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/chongqing_jinfo_mountain_sa_02.jpg'),
  ('金佛山', 2, '', '古佛洞', '<p>Gufo Cave lies west of Yaochiba at about 2,000 m and is the largest explored karst cave on Jinfo Mountain, with a total passage length of about 3 km and a developed tour route of roughly 1.2 km. Natural stone Buddha carvings at the entrance—believed to have been chiseled by monks in the Ming–Qing era from existing rock formations—gave the cave its name ("Ancient Buddha"). The interior is vast: the largest chamber rises about 30 m high and exceeds 5,000 m² in area, filled with stalagmites, stalactites, columns, curtains and cave flowers. The "Sea-Calming Pillar," a 15 m-tall, 1 m-diameter column, is the cave''s signature feature. Warm-yellow lighting enhances the Buddhist atmosphere, with several stone Buddha figures and sutra inscriptions along the route. The cave holds at 11–14 °C year-round with high humidity—wear non-slip footwear. The full walk takes 50–70 minutes.</p>', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/chongqing_jinfo_mountain_sa_03.jpg'),
  ('金佛山', 3, '', '金佛顶', '<p>At about 2,238 m, Jinfo Summit is the highest point and spiritual symbol of Jinfo Mountain. The mountain takes its name from the main ridge''s resemblance to a reclining Buddha when seen from a distance, and the summit occupies the "head" position. From the top, visitors can survey 360° of the Dalou range; on clear days the Guizhou Dalou main ridge and Nanchuan city are visible. Nearby stands Jinfo Temple (Fengzui Temple), the mountain''s Buddhist heart—originally founded in the Song dynasty with later reconstructions, housing statues of Shakyamuni and Guanyin. The summit viewing platform with safety rails is the premier spot for sunrise, sea of clouds, "Buddha''s halo" and stargazing. In winter, snow can accumulate to tens of centimeters, creating a rare southern snow-field scene. The walk from Qianniuping Sky Street takes 40–50 minutes, partly on stone steps.</p>', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/chongqing_jinfo_mountain_sa_04.jpg'),
  ('金佛山', 4, '', '生态石林', '<p>Covering about 2 km² south of Yaochiba at roughly 2,000 m, the Ecological Stone Forest is a key element of Jinfo Mountain''s karst landscape. Unlike the bare stone teeth of Yunnan''s Shilin, Jinfo''s pinnacles and stone buds are cloaked in moss, ferns, shrubs and trees—stone and forest merged into one, earning the name "living stone forest." The pinnacles, 3–8 m tall, take myriad forms—swords pointing skyward, beasts crouching among trees—interspersed with arrow bamboo, rhododendron and rare square bamboo, creating a unique "forest-on-stone" micro-ecosystem. In 2014 Jinfo Mountain was inscribed as part of the "South China Karst" Phase II World Natural Heritage, with the Ecological Stone Forest as a core heritage element. Boardwalks and interpretive signs guide visitors through a 30–40 minute walk—the best outdoor classroom for the mountain''s karst geology and biodiversity.</p>', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/chongqing_jinfo_mountain_sa_05.jpg'),
  ('金佛山', 5, '', '西门索道下站', '<p>The West Gate Cableway Lower Station sits at the foot of Jinfo Mountain''s west slope at about 700 m—the starting point of the western passenger cableway. At roughly 2.4 km long with a 1.3 km elevation gain, the 15-minute ride is the longer and more scenically varied of Jinfo Mountain''s two cableways. Cabins climb along a ridge, offering aerial views of primeval forest, stream-fed waterfalls and distant cloud seas; autumn foliage and winter rime-and-ice scenes are spectacular. The lower station has a waiting hall, ticket windows and a parking lot, plus an adjoining west-slope visitor center and dining facilities. The western route generally has fewer visitors and shorter queues than the north slope, ideal for self-drivers arriving via the western G65 expressway. An outside platform frames the western face of the main summit ridge.</p>', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/chongqing_jinfo_mountain_sa_06.jpg'),
  ('金佛山', 6, '', '西门游客中心', '<p>The West Gate Visitor Center stands at the foot of the west slope beside the West Gate Cableway Lower Station, serving as the main entrance and service hub for the western route. The building blends modern functionality with mountain vernacular style, housing a large ticketing hall, self-service kiosks, an information desk, luggage storage, rain-poncho rental and a first-aid point, where visitors can purchase admission, cableway and shuttle combo tickets. Outside are a large parking lot, restrooms, dining outlets and specialty shops selling square-bamboo shoots, Nanchuan rice and dried local produce. Inside, a geology-and-biodiversity exhibit uses panels and specimens to introduce Jinfo Mountain''s World Natural Heritage karst geology, rare flora and fauna and rhododendron resources—an ideal "knowledge stop" before heading uphill. The walk from the center to the cableway lower station is about 3 minutes.</p>', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/chongqing_jinfo_mountain_sa_07.jpg'),
  ('金佛山', 7, '', '碧潭幽谷', '<p>Located at 700–1,000 m elevation on Jinfo Mountain''s north slope, Bitan Valley is the key lower-zone landscape along the route from the main gate to the cableway lower station. The roughly 3 km gorge winds up along a mountain stream between steep, densely forested cliffs that shelter rare species such as yew and dove tree. Over a dozen deep pools dot the valley—the largest, "Bitan" (Emerald Pool), is jade-green and translucent, traditionally said to be where ancient monks washed their alms bowls. Wooden boardwalks and stone paths pass waterfalls, cascades and moss-covered walls; summer temperatures run 5–8 °C cooler than the base, making this a classic hot-season hiking route. The full walk takes about 1.5–2 hours.</p>', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/chongqing_jinfo_mountain_sa_08.jpg'),
  ('金佛山', 8, '', '索道下站', '<p>The lower station of Jinfo Mountain''s north-slope cableway sits at about 1,100 m above Bitan Valley and is the mountain''s most critical transit hub. The cableway spans roughly 1,100 m with an elevation gain of about 600 m; each cabin holds dozens of passengers and the ride takes about five minutes, offering aerial views of gorges and primeval forest. The lower station has a waiting hall, ticket windows and a rest area; queues at peak times can reach 30–60 minutes, so off-peak travel is advised. An outside viewing platform frames the main summit ridge and serves as a key photo spot for winter snow and autumn foliage. Exiting the upper station places you at Qianniuping Sky Street—the gateway to the summit zone. The cableway may suspend operations in high wind or thunderstorms.</p>', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/chongqing_jinfo_mountain_sa_09.jpg'),
  ('金佛山', 9, '', '牵牛坪天街', '<p>Qianniuping Sky Street lies at the exit of the north-slope cableway upper station at about 2,000 m, named after the Qianniuping meadow. It is the hub of Jinfo Mountain''s summit zone, with restaurants, specialty shops, a convenience store, a café and viewing terraces offering local delicacies such as square-bamboo shoots, Jinshan cured meat and alpine potatoes. A large route map at the plaza helps visitors choose directions: east to Golden Turtle and Cloud Walkway, west to Medicine Pool Dam and Ancient Buddha Cave, north to Arrow Bamboo Forest and Azalea Prince. In winter the street becomes the ski-service center with equipment rental and access to the ski slope. Lodging here makes summit sunrise and stargazing possible.</p>', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/chongqing_jinfo_mountain_sa_10.png'),
  ('金佛山', 10, '', '箭竹林海', '<p>The Arrow Bamboo Forest Sea covers over 10 km² at 1,900–2,100 m on Jinfo Mountain''s summit, dominated by West-China arrow bamboo (Fargesia) standing 2–4 m tall in dense, sun-dimming stands. As a core zone of the national nature reserve, it shelters rare species such as musk deer, golden pheasant and white-crowned fork-tail, and lies along the southern potential corridor of the giant panda''s historical range. Wooden boardwalks thread through the groves—rustling leaves and cool breezes in summer, golden-tipped bamboo contrasting with autumn colors. Arrow bamboo flowers once every 60–120 years, after which entire stands die off and naturally regenerate, a key research subject for the mountain''s ecologists. An eco-education signboard and rest pavilion mark the entrance.</p>', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/chongqing_jinfo_mountain_sa_11.png'),
  ('金佛山', 11, '', '金龟朝阳', '<p>Golden Turtle Facing the Sun perches on the eastern cliff edge of Qianniuping at about 2,100 m and is one of Jinfo Mountain''s most recognizable rock formations. Shaped from Cambrian limestone over hundreds of millions of years of weathering and dissolution, the roughly 10 m long, 5 m high boulder resembles—when viewed from the east—a giant stone turtle lifting its head toward the sun, its shell, head and limbs clearly defined. Facing open valleys to the east, it is the mountain''s premier sunrise spot: dawn clouds churn, the sun crests the ridge, and golden light floods the turtle''s back. A wooden viewing platform with safety rails and an interpretive sign stands here; connecting trails lead to the Cloud Walkway and cliff-hugging plank road, making it the key node of the summit''s eastern route.</p>', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/chongqing_jinfo_mountain_sa_12.jpg'),
  ('金佛山', 12, '', '云端步道', '<p>The Cloud Walkway runs along the cliff face between Qianniuping and Golden Turtle at 2,000–2,100 m, stretching about 1.5 km—the most iconic aerial route on Jinfo Mountain''s eastern summit. Carved along a karst escarpment with sections of cantilevered steel, it places a rock wall on one side and a plunging valley on the other; when mist swirls in, walking it feels like treading on clouds—hence the name. Three projecting viewing platforms offer views of the Nanchuan mountain ranges and the lower-zone gorges, and are prime spots for the mountain''s "Buddha''s halo" and sea of clouds. The full route has safety rails and anti-slip surfacing; it may close in rain, and those with acrophobia should proceed with caution. A safety signboard and rest pavilion mark the entrance.</p>', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/chongqing_jinfo_mountain_sa_13.jpg'),
  ('金佛山', 13, '', '燕子洞和灵观洞', '<p>Swallow Cave and Lingguan Cave lie about 200 m apart on the west side of Qianniuping and form key parts of Jinfo Mountain''s karst-cave system. Swallow Cave has a roughly 15 m wide, 8 m high entrance opening into a spacious chamber where thousands of rock swallows nest year-round; in spring and summer they dart in and out like dark arrows—hence the name. Inside, an underground stream and stalagmites, curtains and flowstone decorate the chamber. Lingguan Cave is named for a Daoist Lingguan statue once placed at its mouth; its interior features stalactites, columns and cave flowers, with some walls bearing natural "Buddha" silhouettes where monks and Daoist priests once practiced. Both caves are lit and equipped with boardwalks; the interior temperature holds at 12–15 °C, so an extra layer is advisable in summer. Visiting both takes about 40–60 minutes.</p>', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/chongqing_jinfo_mountain_sa_14.jpg'),
  ('金佛山', 14, '', '杜鹃王子', '<p>The "Azalea Prince" stands at the edge of the Arrow Bamboo Forest at about 2,050 m—an estimated 1,000-year-old wild Rhododendron rex, roughly 12 m tall, 40 cm in trunk diameter and nearly 8 m across the crown, making it the largest ancient wild rhododendron discovered on Jinfo Mountain. The mountain is a diversity center for Chinese rhododendrons, hosting over 40 species including more than 10 endemics. Each April–May the Prince bursts into bloom, its 10 cm-wide flowers ranging from pink to deep crimson, layered against a backdrop of bamboo, moss and multicolored forests—the most photographed spot of Jinfo Mountain''s spring season and a key site for botanical education. A boardwalk, viewing platform and interpretive sign stand beside the tree.</p>', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/chongqing_jinfo_mountain_sa_15.jpg'),
  ('九街', 0, '', '九街标志牌坊', '<p>The Jiujie Gateway Archway stands at the entrance of Guanyinqiao Jiujie, serving as the symbolic portal of this renowned nightlife district. Built in traditional Chinese architectural style with upturned eaves, painted beams, and the characters "Jiujie" inscribed at the center, it exudes grandeur. By day, the archway appears stately and classical; by night, illuminated lights blend with surrounding neon, creating a striking fusion of old and new. As the landmark of Jiujie, it is a must-visit photo spot for tourists and the starting point for exploring the area''s vibrant nightlife. Surrounded by shops and restaurants ranging from traditional hotpot to trendy bars, it is the perfect gateway to experience Chongqing''s urban night culture.</p>', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/chongqing_jiujie_sa_01.jpg'),
  ('九街', 1, '', '九街高屋', '<p>Jiujie High House is one of the most iconic commercial complexes in the Guanyinqiao Jiujie business district, renowned for its distinctive high-rise facade and diverse mix of businesses. The building features a modern glass curtain wall exterior with dazzling nighttime lighting, forming a brilliant highlight in the Jiujie skyline. Inside, it houses popular internet-famous restaurants, trendy boutique shops, KTV venues, and live houses, making it a hotspot for young people''s nightlife socializing. Multiple themed terraces offer panoramic views of the bustling Jiujie nightscape. Whether enjoying creative cuisine, live music, or drinks with friends, Jiujie High House provides a one-stop urban nightlife experience and is a must-visit destination to feel the charm of Chongqing''s sleepless city.</p>', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/chongqing_jiujie_sa_02.jpg'),
  ('九街', 2, '', '鲤鱼池42号文创园', '<p>Liyuchi No. 42 Cultural and Creative Park was formerly an old industrial factory in Chongqing. After careful renovation, it has been revitalized into a cultural space combining art exhibitions, creative design, specialty dining, and leisure entertainment. The park preserves the rugged framework of the original industrial architecture, with red brick walls and steel structures complementing each other. Weathered traces of time blend ingeniously with modern art installations, creating a unique retro-artistic atmosphere. The park houses numerous independent designer studios, handicraft workshops, boutique cafés, and niche art galleries, and regularly hosts creative markets and art salons. Large-scale graffiti murals on weathered walls are popular photo backdrops for young visitors. Away from the bustle of Jiujie, it offers a quiet, inspiration-filled haven for art and creativity lovers.</p>', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/chongqing_jiujie_sa_03.jpg'),
  ('九街', 3, '', '九街后街', '<p>Jiujie Back Street refers to the alleyway area behind Jiujie''s main street, offering a stark contrast to the neon-lit bustle of the main thoroughfare with a more authentic taste of everyday Chongqing life. Narrow alleys are lined with small food shops serving local delicacies—from steaming bowls of hot and sour noodles and soft glutinous rice cakes to sizzling skewers and fragrant tofu noodles—gathering the most genuine flavors of Chongqing''s streets. There are no upscale restaurants here, only the most down-to-earth tastes and the warmest proprietors. Many locals'' late-night favorites are hidden in these alleys, where an unassuming shop may have been passed down for decades. Walls are adorned with lively graffiti and old-Chongqing-themed murals. Strolling through feels like stepping into a vivid scroll painting of Ba-Yu street life, making it the perfect place to experience authentic Chongqing food culture and neighborhood charm.</p>', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/patch-v2/chongqing_jiujie_sa_04.jpg'),
  ('来福士', 0, '', '朝天门广场与两江交汇', '<p>Chaotianmen Square sits at the confluence of the Yangtze and Jialing rivers, and has been Chongqing''s water gateway and urban origin since ancient times. Standing at the front railing, visitors can see the jade-green Jialing River on the left and the muddy-yellow Yangtze on the right, forming a striking two-color waterline where the rivers meet. Chaotianmen was first built in the early Ming Dynasty and was the largest of the seventeen ancient city gates. Today, after multiple renovations, the square has become a core landmark for leisure and sightseeing. Below lies Chaotianmen Pier, where nightly river cruise boats depart. The Raffles City complex rises behind the square like a cluster of sails, creating a dialogue between old and new. At night, dazzling lights from both banks reflect on the water, making it one of the best spots to photograph Chongqing''s nightscape.</p>', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/chongqing_raffles_city_sa_01.png'),
  ('来福士', 1, '', '购物中心中庭与山城花园', '<p>The Raffles City shopping mall atrium draws inspiration from Chongqing''s mountainous terrain, creating a tiered, three-dimensional space that mimics the traditional stilt-house architecture built along hillsides, cleverly blending commercial space with the city''s topography. The atrium rises dozens of meters with skylights flooding natural light, and cascading greenery hangs from above to create an immersive rainforest-like atmosphere. The Mountain City Garden, located on the mall''s rooftop, is an open-air sky garden featuring over a hundred plant species native to Chongqing or adapted to subtropical climates. Winding paths connect multiple resting spots and viewing nodes overlooking the Jialing River and Chaotianmen Square—a peaceful urban oasis. The mall hosts international and local designer brands, and the atrium regularly features art exhibitions and seasonal installations, elevating the shopping experience into a cultural journey.</p>', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/chongqing_raffles_city_sa_02.png'),
  ('来福士', 2, '', '水晶连廊（探索舱·观景台）', '<p>The Crystal is the most iconic architectural element of Raffles City—a approximately 300-meter-long crystal bridge spanning the tops of four 250-meter-tall towers, suspended like a crystal arc above the mountain city''s skyline. Designed by internationally acclaimed architect Moshe Safdie, it draws inspiration from the "sail" imagery of Chongqing''s millennia-old shipping culture. The Exploration Deck, located inside the Crystal, is the public observation experience area. Through floor-to-ceiling panoramic glass walls, visitors can enjoy 360-degree views of the Yangtze and Jialing rivers'' confluence, the rolling peaks of Nanshan in the distance, and Yuzhong Peninsula''s urban forest below. Interactive exhibits introduce Chongqing''s river geography and urban evolution, with high-definition telescopes and AR devices. At sunset, golden light floods the river—the best time to photograph the two-river confluence and Chaotianmen panorama.</p>', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/chongqing_raffles_city_sa_03.png'),
  ('来福士', 3, '', '探索舱·云端乐园', '<p>The Exploration Deck · Sky Wonderland is an upgraded immersive experience within the Crystal, combining technology interaction, art installations, and themed adventure on top of basic observation. The wonderland features multiple themed zones: the City Memory Zone uses holographic projections and touchscreens to showcase Chongqing''s millennia of evolution from ancient pier to modern metropolis; the River Exploration Zone uses VR to simulate the thrilling experience of boating through two-river gorges; the Star Walk Zone features an LED starry sky ceiling creating a dreamy atmosphere of walking among clouds and galaxies. The most popular attraction is the high-altitude glass observation walkway—a transparent glass floor suspended 250 meters above Chaotianmen Square and the river confluence, offering the ultimate thrill of walking on air. A themed merchandise shop and cloud-top café let visitors enjoy afternoon tea at altitude. The full experience takes about 1.5 to 2 hours, making it Raffles City''s most popular in-depth attraction.</p>', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/chongqing_raffles_city_sa_04.png'),
  ('李子坝轻轨穿楼', 0, '', '轨道李子坝站1号出口', '<p>Metro Liziba Station Exit 1 is located on the side of the station building facing the Jialing River, serving as the primary entrance for visitors to experience the train-through-building marvel up close. Following the signs from inside the station to Exit 1, the moment you push open the glass doors and look up, you can see Line 2 trains gliding through the residential building overhead, just an arm''s length away. The engine sound and laundry hanging from residents'' windows create a fascinating coexistence. Simple guideboards and marked photo spots outside the exit indicate the best shooting angles and approximate train schedules. Many visitors linger here waiting for the perfect moment a train passes through, pressing the shutter to capture this urban wonder. The exit connects directly to Liziba Zheng Street, with steps leading down to the observation platform, making it the natural starting point for exploring the entire attraction.</p>', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/chongqing_liziba_monorail_sa_01.png'),
  ('李子坝轻轨穿楼', 1, '', '李子坝观景平台', '<p>The Liziba Observation Platform is located on the Binjiang Road side of the Jialing River opposite Liziba Station. It was specially built by the Yuzhong District government in 2017 to provide a safe, spacious shooting space for the growing number of visitors. Covering approximately 1,500 square meters, the platform features a cantilevered steel structure extending several meters toward the Jialing River, offering an extremely open view. Looking up from here, the scene of Line 2 trains passing through the 6th to 8th floors of the residential building is fully visible—the best position for the classic train-through-building shot. Colorful graffiti and marked photo spots on the platform floor indicate recommended distances for shooting. The platform is equipped with sunshades, seating, drinking water facilities, and an electronic display showing real-time train arrival information. During holidays, the platform is packed with visitors and cameras, making it one of Chongqing''s most popular internet-famous spots.</p>', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/chongqing_liziba_monorail_sa_02.png'),
  ('李子坝轻轨穿楼', 2, '', '岩之魂浮雕文化墙', '<p>The Spirit of Rock Relief Culture Wall is located on the hillside retaining slope next to the Liziba Observation Platform—a large relief art group created on the existing retaining wall surface. The relief spans over 100 meters in length and several meters in height, with Chongqing''s unique landscape and cultural history as its creative thread. Classic Ba-Yu imagery—stilt houses, stone-paved roads, riverside piers, boat trackers, and old city gates—are layered and carved into the rock face. From afar it resembles an unfolded giant scroll; up close, rich details emerge: an old man carrying water, children at play, fishing boats rowing on the river—each scene vividly recreating old Chongqing''s street life. The relief combines realistic and impressionistic techniques, with bold, powerful lines and distinct light-and-shadow layers that produce different visual effects under varying sunlight. The wall not only beautifies the otherwise plain slope but also adds a cultural immersion experience for visitors waiting for trains, making it an unmissable artistic highlight of the Liziba area.</p>', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/chongqing_liziba_monorail_sa_03.png'),
  ('李子坝轻轨穿楼', 3, '', '文旅服务中心', '<p>The Cultural Tourism Service Center is located near the Liziba Observation Platform, serving as the core supporting facility for the entire Liziba train-through-building attraction. The center features a modern, clean glass-curtain-wall exterior that creates an interesting contrast with the surrounding old mountain-city streets. Inside, it has four functional zones: a visitor information desk, rest area, cultural merchandise display area, and multimedia experience area. The information desk is staffed with bilingual (Chinese-English) personnel providing attraction maps, train schedules, and nearby dining recommendations. The rest area offers comfortable seating and free drinking water for visitors waiting between train pass-throughs. The merchandise area sells train-through-building-themed souvenirs including fridge magnets, postcards, hand-drawn maps, and 3D assembly models. The multimedia area plays documentaries about the construction of Liziba Metro and 360-degree panoramic footage on large screens, letting visitors understand the story behind this engineering marvel. The center also provides luggage storage and barrier-free access, making it the ideal first stop and supply point.</p>', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/chongqing_liziba_monorail_sa_04.png'),
  ('李子坝轻轨穿楼', 4, '', '巴渝旧闻馆', '<p>The Ba-Yu Old News Gallery is a distinctive cultural venue within the Liziba train-through-building attraction, themed around modern Chongqing newspapers and journalism. Through physical exhibits, illustrated panels, and multimedia interactives, it presents a century of evolution in Chongqing''s press and public opinion—from the late Qing and early Republic to the reform and opening-up era. The gallery houses a collection of original and reprinted old newspapers, including historically significant titles such as Chongqing Daily, Xin Shu Bao, and Ta Kung Pao, whose front pages record major historical moments of Chongqing as wartime capital, industrial hub, and municipality. An "Old Papers, New Read" interactive station lets visitors browse electronic versions of vintage newspapers via touchscreen, experiencing the reading feel of the lead-type era. Themed wall panels connect key nodes in Chongqing''s press history—from the story of Baixiang Street''s "Newspaper Row" to the wartime years of Xinhua Daily in Chongqing. This micro-gallery hidden beside the train-through-building offers visitors a unique window into understanding Chongqing through the lens of journalism.</p>', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/chongqing_liziba_monorail_sa_05.png'),
  ('李子坝轻轨穿楼', 5, '', '轨道穿楼主体建筑', '<p>The train-through-building main structure is a multi-use residential-commercial building on Liziba Zheng Street in Yuzhong District, built in the early 2000s, and also the station building for Liziba Station on Chongqing Metro Line 2. The 19-story building houses the metro platform and tracks on the 6th to 8th floors, with trains passing directly through the middle of the structure. The lower floors (1–5) contain shops, and the upper floors (9–19) house residential apartments. This unique "rail-residential coexistence" design is extremely rare both nationally and globally. Its secret lies in the independent load-bearing structure and vibration isolation system between the track level and residential floors—track beams are supported by dedicated columns completely separated from the residential floor slabs, so residents upstairs barely feel vibration or noise when trains pass through. The exterior is clad in light-colored tiles, with two square openings where trains emerge and re-enter serving as the most recognizable visual symbols. Each time a train roars through, the massive body emerging from and disappearing into the building is a textbook example of urban architecture and rail transit integration, making this building one of Chongqing''s most famous city cards.</p>', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/chongqing_liziba_monorail_sa_06.png'),
  ('山城步道', 0, '', '步道入口牌坊', '<p>The Trail Entrance Archway stands at the main entrance of Shancheng Trail on Zhongxing Road in Yuzhong District, a stone archway combining traditional Ba-Yu architectural style with modern urban wayfinding. It features a four-pillar, three-bay structure in blue-gray stone, with gilded characters "山城步道" (Shancheng Trail) engraved on the crossbeam and couplets depicting old Chongqing street life carved on the flanking pillars—solemn, classical, and highly recognizable. Behind the archway begins the trail''s core uphill section, where stone steps wind upward along the mountainside, with old residences and new viewing platforms alternating on both sides. The moment you pass beneath the archway, you officially enter the time corridor of Shancheng Trail. A small plaza in front of the archway features a trail map and historical introduction panels, making it the first stop for visitors to understand the full route and plan their walk. The archway itself is a popular photo spot—especially at dusk when warm lights illuminate the carved characters against the layered silhouette of mountain-city buildings behind.</p>', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/chongqing_mountain_trails_sa_01.png'),
  ('山城步道', 1, '', '厚庐', '<p>Houlu Residence is a historically significant Republic-era building along the middle section of Shancheng Trail, originally built in the 1930s–40s during the War of Resistance as a private mansion of a military-political official. The two-story brick-and-wood structure faces north and is built against the hillside, with a blue-brick facade, traditional gray-tile roof, clean eave lines, and a portico supported by square pillars—reflecting the East-meets-West architectural style of the Republic era, combining the solid simplicity of traditional Ba-Yu dwellings with the geometric order of Western architecture. The name "Houlu" derives from the Chinese saying "thick virtue carries all things," and the stone plaque above the doorway remains well-preserved. The interior retains original wooden staircases, latticed windows, and period furnishings, offering a time-travel experience back to the wartime era. Several other contemporary buildings surround Houlu, forming a relatively complete Republic-era architectural cluster. As a key node in Shancheng Trail''s historical fabric, Houlu is not just a building but a microcosm of Chongqing''s memory as the wartime capital.</p>', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/chongqing_mountain_trails_sa_02.png'),
  ('山城步道', 2, '', '悬空栈道', '<p>The Suspended Cliffside Walkway is the most visually striking and experiential section of Shancheng Trail, built cantilevered off the cliff face in Yuzhong District. It extends over 100 meters with a width of 1.5 to 2 meters, with sections paved in transparent glass, revealing the vertical cliff drop of tens of meters below and the layered rooftops of the old town—an experience of pure visual thrill. The walkway uses steel beams as its skeleton, with anti-corrosion wood and tempered glass as surface materials, and stainless steel railings with wire mesh that minimize visual obstruction while ensuring safety. Walking along, one side is the solid mountain rock face, the other an abruptly open panorama—distant views of the Yangtze River and the South Bank skyline, close-up views of the dense gray-tiled rooftops and crisscrossing stone alleys of Shancheng Lane''s old quarter. On clear days, sunlight refracts through the glass panels in dappled patterns, creating a fascinating contrast with the old-town atmosphere below. At dusk, it is a prime spot to watch sunset glow illuminate the Yangtze, as warm orange light intertwines with the mountain-city skyline, forming a three-dimensional landscape painting unique to Chongqing.</p>', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/chongqing_mountain_trails_sa_03.png'),
  ('山城步道', 3, '', '仁爱荒野剧场', '<p>Ren''ai Wilderness Theater is located on the upper section of Shancheng Trail, on the site of the former Ren''ai Church. After a thoughtful redesign, it has become an open-air theater blending historical ruins with wild aesthetic sensibility. The preserved remnants of the old church serve as a backdrop—stone walls covered in vines and moss, where the mottled marks of time contrast with and complement new plant growth. The center features a semicircular terraced stone seating area accommodating about 100 people, with a simple stage built from reclaimed wood and stone. The overall design is rugged and unadorned yet reveals carefully curated artistic intention at every turn. Native wildflowers and ornamental grasses surround the theater—lush and fragrant in spring and summer, evoking a melancholy poetry of bare branches in autumn and winter. Small concerts, poetry readings, theatrical performances, and outdoor screenings are held here regularly, and the space often becomes a spontaneous gathering spot for street artists and creative souls. Even on days without performances, simply sitting in this ruin-garden listening to wind and birdsong while gazing at the mountain-city skyline is enough to feel the unique cultural warmth and romantic undertone of Chongqing.</p>', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/chongqing_mountain_trails_sa_04.png'),
  ('十八梯', 0, '', '十八梯大牌坊', '<p>The Shiba Ti Grand Archway stands at the southern entrance of the Shiba Ti Traditional Heritage District, serving as the first landmark for visitors entering this century-old street. Built from blue stone in a four-pillar, three-bay sky-reaching style, it stands over ten meters tall—imposing yet refined and elegant. The central plaque is inscribed with three gold-leaf characters reading "Shiba Ti," while the crossbeams feature relief carvings of bats, auspicious clouds, and ruyi patterns. The stone-drum pillar bases are finely carved, combining the robustness of Ba-Yu stone carving with the gracefulness of southern Chinese archways. A small plaza surrounds the archway with faux-antique stone paving, ficus bonsai, and decorative lamp posts. After dark, warm yellow lights illuminate the stone structure, creating a rich atmosphere of old Yuzhou charm. Looking north from here, the main street of Shiba Ti unfolds in cascading stone steps descending the hillside, with stilt-house-style shops lining both sides, and modern skyscrapers in the distance overlapping with tiled eaves nearby. A guide map and electronic touch screen beside the archway mark all attractions and recommended routes, making it an essential stop for planning visits and taking photos.</p>', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/chongqing_shibati_sa_01.png'),
  ('十八梯', 1, '', '善果巷与山城记忆馆', '<p>Shanguo Lane is a historic stone-step alley within the Shiba Ti Heritage District. Its name originates from the Shanguo Temple that once stood here during the Qing Dynasty, carrying forward the spirit of charity and goodwill. The alley is about two meters wide, bordered by old brick walls and stone embankments intertwined with ficus tree roots, covered in moss and draped with vines—walking through it feels like traveling back to the slow-paced old Chongqing. Within the lane sits the Mountain City Memory Hall, a micro-museum converted from a traditional residence. With its grey tiles, white walls, and wooden windows, the exterior is understated, yet stepping inside reveals a hidden world. The hall uses "Upper City and Lower City" as its theme, presenting through old photographs, vintage objects, oral history videos, and interactive installations the century-long evolution of Shiba Ti—from the bustling pier trade of the late Qing and early Republic, through the wartime capital''s population surge, to modern urban renewal. Exhibits include old kerosene lamps, bamboo-woven thermos flasks, hand-written street signs, and yellowed household registers—everyday objects full of warmth that bear authentic witness to ordinary Chongqing residents'' lives. A "sound wall" features recordings of street hawker cries, work chants, and riverboat whistles—put on the headphones and listen to the vanishing sounds of the mountain city.</p>', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/chongqing_shibati_sa_02.png'),
  ('十八梯', 2, '', '月台坝（山地院落）', '<p>Yuetai Ba is located mid-way along Shiba Ti—a cluster of terraced courtyard residences naturally formed by the hillside gradient, and one of the nodes that best embodies Chongqing''s mountain architecture within the entire heritage district. The name "Yuetai" (Moon Platform) comes from the broad, flat stone platform in front of the courtyards, shaped like a moon terrace. In the past, residents gathered here to cool off, chat, dry laundry, and let children play—it was the heart of neighborhood social life. The courtyard complex features timber frame structures with blue brick and stone walls, stepping down the slope in successive terraces. Looking up from below, rows of grey-tiled eaves rise like steps; looking down from above, courtyards, skylights, and stone stairs interlock in rich spatial layers. After renovation, Yuetai Ba retains its original architectural bones and spatial fabric, with damaged components restored using traditional craftsmanship, while new businesses—creative shops, teahouses, and craft workshops—have been introduced. Narrow stone-step alleys connect the courtyards, with stone water vats and ficus bonsai at corners, revealing the old Chongqing philosophy of "climbing slopes and turning corners" everywhere. Sitting in a bamboo chair on the moon platform with a bowl of covered tea, overlooking the half-cityscape and distant river views, is the most authentic way to experience the slow life of the mountain city.</p>', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/chongqing_shibati_sa_03.png'),
  ('十八梯', 3, '', '大隧道遗址', '<p>The Shiba Ti Great Tunnel Relics are a vital part of Chongqing''s WWII air defense engineering. After the Nationalist Government relocated the capital to Chongqing in 1937, Japanese forces conducted indiscriminate strategic bombing of the city for five and a half years. To protect civilian lives, Chongqing mobilized the entire city to excavate a massive network of air-raid shelter tunnels. The Shiba Ti Great Tunnel was one of these, approximately 2 km long, carved by hand into sandstone hillside. The interior stands about 2 meters high and 2–3 meters wide, capable of sheltering thousands simultaneously. The tunnel was equipped with ventilation shafts, drainage channels, rest areas, and rudimentary medical stations—crude conditions that nonetheless saved countless lives during the darkest years. The now-open section has been safety-reinforced and scenically restored. Chisel marks and smoke stains from the era remain visible on the walls. Information panels and multimedia installations inside detail the historical background of the Chongqing Bombing, the tunnel construction process, and civilian shelter life. Walking through, one hears simulated air-raid sirens and infants'' cries, creating a profound sense of the resilience and survival spirit of the Chongqing people during those fiery years—a historically educational immersive site.</p>', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/chongqing_shibati_sa_04.png'),
  ('武隆喀斯特旅游区', 0, '', '天龙桥', '<p>Tianlong Bridge is the first natural stone arch bridge in Wulong''s Three Natural Bridges scenic area and the most imposing of the three. The bridge was formed from limestone deposited on an ancient seabed hundreds of millions of years ago, subsequently uplifted by tectonic movement and sculpted by water erosion and collapse. The arch stands approximately 235 meters high, with a bridge deck about 150 meters thick, 147 meters wide, and a span of about 34 meters—like a colossal stone rainbow spanning two cliff faces. The irregularly shaped arch opening allows sunlight to pour through from above, casting dappled light and shadow across the valley floor in a magnificent, dreamlike display. A winding stone-paved trail passes beneath the bridge, with ferns and vines clinging to the rock walls and moss-covered rubble scattered about, as if entering an ancient secret realm. The most famous feature is an eagle-shaped natural rock formation at the top of the arch and the "Thread Spring" trickling from beneath the vault. The hidden courier station from Zhang Yimou''s film "Curse of the Golden Flower" was filmed beneath Tianlong Bridge, and the replica structure remains as a must-visit photo spot. Walking beneath the bridge and looking up at the enormous vault overhead, one feels the overwhelming majesty of nature and the smallness of humanity.</p>', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/chongqing_wulong_karst_sa_01.png'),
  ('武隆喀斯特旅游区', 1, '', '仙女山国家公园-木梯子站', '<p>Mutizi Station is the starting station of the sightseeing train within Fairy Mountain National Park, located near the main park road entrance at an elevation of about 1,900 meters—the first stop for visitors entering the core scenic area. The name "Mutizi" (Wooden Ladder) originates from local history: a steep mountain path once paved with wooden stairs here was the main route for early mountain dwellers to gather herbs and graze livestock. After the road was built, the stairs fell into disuse, but the name endured. The station building features wooden construction with grey tiles in Ba-Yu mountain vernacular style, harmonizing with the surrounding pine forest and alpine meadows. The plaza in front includes a large visitor distribution area, ticket windows, a resting corridor, and park maps. After purchasing tickets, visitors board a vintage sightseeing train that runs along a circular railway through the park. The 12-kilometer route passes through dense Cryptomeria and cypress forests and alpine meadows with seasonal variation: lush green grass and wildflowers in spring and summer, layered autumn colors, and a silvery snowscape in winter resembling northern landscapes. Mutizi Station also houses a transfer center and ecological parking lot where self-driving visitors park before taking the train into the core scenic area. An open lawn beside the station is equipped with telescopes for viewing Fairy Mountain''s main peak and the rolling Wuling range—an ideal spot for warm-up photos before departure.</p>', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/chongqing_wulong_karst_sa_02.png'),
  ('武隆喀斯特旅游区', 2, '', '仙女山国家公园-大草原站', '<p>Da Caoyuan Station is the core stop of the Fairy Mountain National Park sightseeing train, located about 4 km after Mutizi Station at an elevation of approximately 2,000 meters. The moment visitors step off the train, the view opens dramatically—a vast alpine meadow stretching to the horizon, covering more than ten square kilometers, often called the "Switzerland of the East." The grassland undulates gently like a green velvet carpet—emerald green with scattered wildflowers in spring and summer (most commonly purple verbena, yellow coreopsis, and white wild strawberry blossoms), with cattle, sheep, and horses grazing peacefully in a pastoral idyll. In autumn, the meadow turns golden brown, contrasting vividly with the dark green Cryptomeria forest in the distance; in winter, thick snow transforms it into a rare southern snowfield, where the park operates a ski area and snow activities. After disembarking, visitors can choose from multiple experiences: horseback riding is the most classic, with local herdsmen leading horses along set routes for a leisurely "vast sky, boundless plain" experience; kite flying is also extremely popular, as the highland winds keep colorful kites dancing overhead; archery, grass sliding, and off-road go-karting are also available. A rest area, snack shop, and yurt-themed restaurant beside the station provide supplies and respite. Da Caoyuan Station is where visitors spend the most time—with most staying at least 2–3 hours to enjoy the abundant activities.</p>', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/chongqing_wulong_karst_sa_03.png'),
  ('武隆喀斯特旅游区', 3, '', '天官赐福', '<p>Tianguan Cifu is a unique natural cliff-face feature beneath Tianlong Bridge in the Three Natural Bridges scenic area. On the inner wall of the northern arch of Tianlong Bridge, a pattern of stone veins—formed over hundreds of millions of years through water erosion and mineral staining—strikingly resembles the four Chinese characters "天官赐福" (Heavenly Official''s Blessing). The strokes appear vigorous and well-structured, as if an immortal had used a finger as a brush to write on the cliff face. This coincidence has circulated in folklore for generations; local people regard it as an auspicious mark bestowed by a heavenly official descending to earth. During New Year and major celebrations, nearby villagers come to burn incense and pray for favorable weather and household peace. The surrounding cliff also bears natural patterns resembling auspicious clouds, bats, and ruyi motifs, further reinforcing the auspicious symbolism of fortune, prosperity, longevity, and happiness. The scenic area has installed a viewing platform, information plaque, and soft lighting so visitors can appreciate this natural wonder under various conditions. Geologically, the pattern results from differential weathering of varying mineral compositions in the limestone and iron oxide staining—a natural formation that, due to its striking resemblance to Chinese characters, has become one of the most culturally significant geological wonders of the Wulong Karst.</p>', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/chongqing_wulong_karst_sa_04.png'),
  ('武隆喀斯特旅游区', 4, '', '青龙桥', '<p>Qinglong Bridge is the second natural stone arch bridge in the Three Natural Bridges scenic area and the tallest of the three, with an arch height of approximately 281 meters, a deck thickness of about 168 meters, a width of about 124 meters, and a span of about 31 meters—ranking among the tallest natural stone arch bridges in the world. The bridge spans a near-vertical karst canyon, resembling a colossal stone archway standing between heaven and earth. The name comes from a beautiful natural phenomenon: at sunrise, sunlight slants through the arch opening, and the light refracts through mist and water vapor to form a blue-green beam crossing the canyon—like an azure dragon soaring through the bridge. A stream flows along the valley floor, with stalactites hanging from the rock walls in various forms—some like swords piercing the ground, others like lotus buds about to bloom. The arch ceiling has developed alcoves and natural stone eaves through weathering. During the rainy season, water cascades from these eaves like a bead curtain, with rainbows appearing in the sunlight—a dreamlike scene. A viewing platform beneath Qinglong Bridge offers one of the best vantage points for photographing the "soaring azure dragon" sunrise spectacle and classic panoramic views of the Three Natural Bridges.</p>', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/chongqing_wulong_karst_sa_05.png'),
  ('武隆喀斯特旅游区', 5, '', '神鹰天坑', '<p>Shenying Tiankeng is a large karst collapse doline situated between Tianlong Bridge and Qinglong Bridge in the Three Natural Bridges scenic area. The doline has an elliptical plan with a rim diameter of about 200–300 meters and a depth of approximately 195 meters, with a total volume of several million cubic meters—a world-class karst collapse feature. The doline is enclosed by nearly vertical limestone cliffs whose surfaces, through differential weathering, have formed numerous lifelike rock formations. The most striking is a protruding boulder on the eastern rim that, from certain angles, resembles a soaring eagle with head held high, wings spread, and piercing gaze overlooking the doline floor—giving the feature its name "Divine Eagle." The doline floor is relatively flat, covered with thick collapse deposits and subsequently grown dense vegetation, forming a relatively isolated "hanging garden" ecosystem. Wildflowers carpet sunlit areas while ferns thrive in shady corners, and birds occasionally circle above. Visitors descend along a cliff-hugging boardwalk, appreciating the doline''s grandeur and the Eagle Rock from different heights and angles. Standing at the bottom looking up, the surrounding walls form a natural shaft with the sky cut into an irregular ellipse where clouds drift overhead—an extraordinary sense of isolation from the world.</p>', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/chongqing_wulong_karst_sa_06.png'),
  ('武隆喀斯特旅游区', 6, '', '黑龙桥', '<p>Heilong Bridge is the third and final natural stone arch bridge in the Three Natural Bridges scenic area, with an arch height of approximately 223 meters, a deck thickness of about 137 meters, a width of about 193 meters, and a span of about 28 meters. Unlike Tianlong Bridge''s grandeur and Qinglong Bridge''s height, Heilong Bridge is renowned for its depth, darkness, and unpredictability. The long, curving arch opening admits little sunlight, leaving the interior perpetually dim with cool breezes and the sound of flowing water—walking through feels like traversing a black dragon''s belly, hence the name "Black Dragon." The most famous feature is the natural perforation in the arch ceiling through which sunlight enters, creating a bright spot on the dark wall that slowly moves over time like a searchlight scanning the cave—dubbed the "Shadow Clock." Multiple remarkable micro-karst formations exist beneath: a stalactite platform resembling Guanyin seated on a lotus, rock strata sections as clean-cut as by knife, and miniature stalagmite clusters formed by perennial dripping. Near the exit, a narrow passage called "Dragon Gate" has walls nearly touching, admitting only one person sideways—after squeezing through, the space suddenly opens into a hidden paradise. Summer temperatures beneath Heilong Bridge are only about 18°C, making it a natural cooling refuge and the most adventure-filled of the three bridges.</p>', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/chongqing_wulong_karst_sa_07.png'),
  ('武隆喀斯特旅游区', 7, '', '龙泉洞', '<p>Longquan Cave is hidden within a limestone cliff face near Heilong Bridge in the Three Natural Bridges scenic area—one of the most mysterious cave features in the park. The entrance is concealed beneath a moss-covered cliff, where a clear mountain spring gushes from within, cascading along the rock face into a thin stream that drops to the valley floor. The perpetual flow and the low, dragon-like rumble of the water give it the name "Dragon Spring." The explored length extends several hundred meters, divided into front and rear chambers. The front chamber is spacious with a vault about 15 meters high, walls covered in diverse stalactites and stone curtains—some like inverted lotus flowers, others like terraced fields or hanging silk drapes—gleaming under lighting. The rear chamber is deeper and narrower, requiring visitors to stoop; the ceiling is dense with soda straw stalactites like a volley of arrows, while several stalagmites and columns rise from the floor. The tallest stalagmite, about 3 meters high, resembles a miniature pagoda, formed over tens of thousands of years of drip deposition. The cave maintains a constant temperature of about 16°C year-round—refreshingly cool in summer and misty in winter. Ancient marine fossils are visible on the cave walls, silently recounting the epic geological journey from ocean floor to mountain peak over hundreds of millions of years. Though smaller than Wulong''s Furong Cave, Longquan Cave''s exquisite delicacy and seamless integration with the Three Natural Bridges make it an unmissable hidden gem.</p>', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/chongqing_wulong_karst_sa_08.png'),
  ('武隆喀斯特旅游区', 8, '', '龙水峡地缝', '<p>Longshuixia Difeng is an important component of the Wulong Karst World Natural Heritage. It belongs to the same geological system as the Three Natural Bridges but presents a dramatically different landscape. The fissure extends about 5 km total with a developed tourist section of about 2 km—a deep gorge-type karst landform formed by the collapse of an underground river''s ceiling. At its narrowest, the gorge is only 1–2 meters wide, with near-vertical cliff walls 200–300 meters high. From the valley floor, the sky appears as a single thread—hence the names "Earth Fissure" and "Thread of Sky." A crystal-clear stream runs the length of the valley floor, jade-green in color, with water-polished boulders scattered throughout. Cliff-hugging boardwalks and suspended bridges wind through the gorge—visitors stroll along the streambank one moment and climb to mid-cliff aerial walkways the next, with only a sliver of sky overhead and rushing water below. Stalactites hang from the walls, thick with moss and ferns, as if entering a green tunnel toward the earth''s core. The microclimate is cool and humid, with air fragrant with plants and water mist; summer temperatures are about 10°C lower than outside. Multiple small waterfalls cascade from cliff crevices along the way, with mist and occasional rainbows. The most spectacular, Yinhe Waterfall, drops dozens of meters—the iconic feature of the fissure.</p>', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/chongqing_wulong_karst_sa_09.png'),
  ('武隆喀斯特旅游区', 9, '', '银河飞瀑', '<p>Yinhe Waterfall is the largest and most awe-inspiring waterfall in the Longshuixia Difeng scenic area. Located at the mid-section of the gorge fissure, an abundant underground river source gushes from a natural crevice high on the cliff face, cascading down a near-vertical rock wall with a drop of several dozen meters. At full flow, the curtain spans 3–5 meters wide, roaring like thunder with mist filling the narrow gorge—an overwhelming spectacle. The great height and force shatter the water into countless fine droplets that refract sunlight into brilliant sparkles, like the Milky Way descending from heaven—hence the name "Milky Way Cascade." At its base, the waterfall collects into a deep emerald pool, clear to the bottom yet unfathomably deep, surrounded by mirror-smooth boulders polished by the current. From the viewing platform at the pool''s edge, mist washes over visitors—refreshingly cool in summer, while in winter it freezes into icicles and frost flowers adorning the cliffs, offering distinct beauty in every season. A natural alcove in the cliff behind the waterfall allows adventurous visitors to circle via a side boardwalk into the cave and look outward through the cascading curtain—a magical "Water Curtain Cave" experience. Yinhe Waterfall is the climactic section of the Longshuixia Difeng tour and one of the most memorable water features in the entire Wulong Karst tourist area.</p>', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/chongqing_wulong_karst_sa_10.png'),
  ('武隆喀斯特旅游区', 10, '', '蛟龙寒窟', '<p>Jiaolong Hangu is located beneath a cliff deep within the Longshuixia Difeng scenic area—a natural large stone cavern formed by the combined action of karst dissolution and rock layer collapse. The entrance is low and concealed, half-hidden by dense ferns and moss, requiring visitors to duck to enter. The interior space covers several dozen square meters with a vault about 3–5 meters high. The walls are covered with grooves and dissolution pits formed by perennial water erosion, their surfaces wet and smooth, gleaming with a cold sheen under lighting. The cavern''s most notable feature is its exceptionally low temperature—about 12–14°C year-round. Even in midsummer, the chill upon entering is biting and bone-penetrating, with a temperature difference of more than 15°C from outside. A shallow cold pool occupies the cavern floor, crystal-clear and icy, inhabited by tiny blind fish and transparent shrimp—cave-dwelling species evolved for perpetual darkness, their bodies pale or colorless. Behind the pool, a narrow underground river channel extends deeper into the earth, its water echoing faintly, with even searchlights unable to reach the end—shrouding the cavern in mystery. Local folklore holds that a flood dragon once lurked here, its dragon breath becoming the perpetual cold mist, hence the name "Flood Dragon Cold Cave." Though modest in size, the extreme chill and mysterious underground ecosystem make this one of the most memorable exploration stops in the Longshuixia Difeng tour.</p>', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/chongqing_wulong_karst_sa_11.png'),
  ('长江索道', 0, '', '北站（渝中区新华路站）', '<p>The North Station of the Yangtze River Cableway is located near the intersection of Xinhua Road and Cangbai Road in the Xiaoshizi commercial area of Yuzhong District—the Yuzhong starting station and the preferred departure point for most visitors. The station building is a multi-story cableway complex with a light grey exterior and a prominent red "Yangtze River Cableway" sign that has become one of the iconic elements of the Yuzhong Peninsula skyline. The ground floor houses the ticket hall and waiting area with self-service machines and staffed windows. During peak season, queues can reach one to two hours—advance booking via the official mini-program is recommended. After purchasing tickets, visitors take an elevator to the high-level platform, a semi-open structure enclosed on three sides and open toward the river. A large floor-to-ceiling glass window lets waiting visitors overlook the dense urban fabric of the Yuzhong Peninsula and the rolling mountains of the south bank. The station''s greatest advantage is that departing cabins ascend from among the Yuzhong Peninsula''s high-rises, cross over the layered city roofline, and suddenly span the Yangtze—the visual transition from "city to river" is spectacular, making it the best starting point for panoramic photos of the peninsula and Yangtze skyline. A cableway history exhibition area beside the station displays archival construction photos and engineering documentation.</p>', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/chongqing_yangtze_cableway_sa_01.png'),
  ('长江索道', 1, '', '索道轿厢', '<p>The Yangtze River Cableway cabin is the core vehicle of the entire cableway experience, suspended on a carrying cable strung high above the Yangtze and hauled by a traction machine between North and South Stations. The cableway was completed and opened in 1987, with a total length of approximately 1,166 meters, a maximum height of about 60 meters above ground, and a one-way journey of about 4–5 minutes. The cabin features a bright yellow exterior, about 6.5 meters long, 1.5 meters wide, and 2 meters high, accommodating about 20–25 standing passengers. Large tempered glass windows on all four sides provide expansive views—the river surface, urban architecture on both banks, and rolling mountains are all clearly visible from front, sides, and below. The ride is unforgettable: the cabin departs slowly from the North Station platform, gradually accelerates, rises among dense city high-rises, and after crossing the north bank levee, the ground below suddenly becomes the open river—the mighty Yangtze flowing eastward, boats shuttling back and forth, with Chaotianmen Raffles City and Dongshuimen Bridge in the distance. At mid-river, the cabin sways gently with dozens of meters of rushing water below—thrilling and magnificent. On clear days, the Nanshan mountain peaks are visible in the distance; on foggy days, the cabin traverses through clouds like riding the mist. A voice guide inside introduces landmarks along the way. Night rides offer the dazzling illuminated skyline of the Yuzhong Peninsula—one of Chongqing''s most iconic urban experiences.</p>', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/chongqing_yangtze_cableway_sa_02.png'),
  ('长江索道', 2, '', '南站（南岸区龙门浩站）', '<p>The South Station of the Yangtze River Cableway is located in the Longmenhao area of Nan''an District, on a riverside highland along the south bank of the Yangtze—the cableway''s southern terminal and the departure station for those boarding from the Nan''an side. Unlike the bustling Xiaoshizi commercial district where the North Station sits, the South Station''s surroundings are more leisurely and artistic—adjacent to the recently restored Longmenhao Old Street historic district, where blue-brick, dark-tile WWII-era buildings cascade up the hillside, dotted with cafés, teahouses, and creative boutiques. The station building is more compact than the North Station, with ticket windows, a waiting area, and a small observation platform. The platform level faces north toward the river, where floor-to-ceiling glass windows offer an unobstructed panoramic view of the entire Yuzhong Peninsula: the Chaotianmen Raffles City twin towers, Hongyadong complex, Qiansimen Bridge, and Jiangbeizui CBD arrayed before you—one of the best positions for photographing the classic Yuzhong Peninsula skyline, especially stunning at sunset and after dark. Riding from the South Station toward the North, the cabin descends from the south bank highland toward the river, with the view transitioning from a panoramic overlook to eye-level with the river surface and then looking up at the Yuzhong Peninsula towers—a perspective complementary to the ascending view from the North Station. A 5-minute walk from the station reaches Longmenhao Old Street, and 10 minutes reaches the Dongshuimen Bridge walkway—an ideal node linking the cableway experience with south bank riverside touring.</p>', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/chongqing_yangtze_cableway_sa_03.png')
), mapped_rows AS (
  SELECT
    CONCAT(a.id, '_sa_', LPAD((i.sort_order + 1)::text, 2, '0')) AS id,
    a.id AS attraction_id,
    i.name_en,
    i.name_zh,
    i.body,
    i.cover_image_path,
    i.sort_order
  FROM input_rows i
  JOIN attractions a ON a.chinese_name = i.attraction_name_zh
)
INSERT INTO sub_areas (
  id, attraction_id, name_en, name_zh, body, cover_image_path, sort_order, is_active
)
SELECT
  id, attraction_id, name_en, name_zh, body, cover_image_path, sort_order, TRUE
FROM mapped_rows
ON CONFLICT (id) DO UPDATE SET
  name_en=EXCLUDED.name_en,
  name_zh=EXCLUDED.name_zh,
  body=EXCLUDED.body,
  cover_image_path=EXCLUDED.cover_image_path,
  sort_order=EXCLUDED.sort_order,
  is_active=EXCLUDED.is_active,
  updated_at=NOW();
